def _create_reset_token(user_id: int) -> str:
    token = secrets.token_urlsafe(32)
    th = _token_hash(token)
    created = _now_utc()
    expires = created + timedelta(seconds=app.config["RESET_TOKEN_TTL_SECONDS"])
    db = get_db()
    db.execute(
        "INSERT INTO mfa_reset_tokens (user_id, token_hash, created_at, expires_at, used_at, used_ip, used_ua) VALUES (?, ?, ?, ?, NULL, NULL, NULL)",
        (user_id, th, _dt_to_str(created), _dt_to_str(expires)),
    )
    db.commit()
    return token

def _consume_reset_token(token: str):
    th = _token_hash(token)
    db = get_db()
    row = db.execute("SELECT * FROM mfa_reset_tokens WHERE token_hash = ?", (th,)).fetchone()
    if not row:
        return None, "invalid_token"
    if row["used_at"] is not None:
        return None, "token_used"
    expires = _str_to_dt(row["expires_at"])
    if _now_utc() > expires:
        return None, "token_expired"
    ip, ua = _client_meta()
    db.execute(
        "UPDATE mfa_reset_tokens SET used_at = ?, used_ip = ?, used_ua = ? WHERE id = ?",
        (_dt_to_str(_now_utc()), ip, ua, row["id"]),
    )
    db.commit()
    return row, None

@app.post("/reset-mfa")
def reset_mfa_request():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()

    # Always return ok to prevent account enumeration
    generic = jsonify({"status": "ok"})

    if not email:
        return generic

    db = get_db()
    user = db.execute("SELECT id, email FROM users WHERE email = ?", (email,)).fetchone()
    if not user:
        return generic

    token = _create_reset_token(user["id"])
    link = app.config["APP_BASE_URL"].rstrip("/") + url_for("reset_mfa_confirm") + "?" + urlencode({"token": token})

    subject = "Reset your MFA settings"
    body = (
        "We received a request to reset multi-factor authentication (MFA) on your account.\n\n"
        "If you requested this, use the link below to disable MFA and sign in with just your password:\n\n"
        f"{link}\n\n"
        f"This link expires in {app.config['RESET_TOKEN_TTL_SECONDS'] // 60} minutes.\n\n"
        "If you did not request this, you can ignore this email."
    )
    send_email(user["email"], subject, body)
