@app.get("/reset-mfa/confirm")
def reset_mfa_confirm():
    token = (request.args.get("token") or "").strip()
    if not token:
        return jsonify({"error": "missing_token"}), 400

    row, err = _consume_reset_token(token)
    if err:
        return jsonify({"error": err}), 400

    db = get_db()
    user = db.execute("SELECT * FROM users WHERE id = ?", (row["user_id"],)).fetchone()
    if not user:
        return jsonify({"error": "user_not_found"}), 404

    db.execute("UPDATE users SET mfa_enabled = 0, mfa_secret = NULL, mfa_recovery_codes = NULL WHERE id = ?", (user["id"],))
    db.commit()

    # Do not log the user in automatically; just confirm reset succeeded.
    return jsonify({"status": "ok", "mfa_enabled": False, "message": "MFA has been reset. You can now log in with just your password."})

